-- ----------------------------
INSERT INTO `planttype` VALUES (1, 'Seed', 'Grows new plants from genetic mix. Slower growth but provides genetic variation. Suitable for starting new varieties.', '2025-12-13 22:37:41');
INSERT INTO `planttype` VALUES (2, 'Marcot', 'Air layering method that roots a branch while still attached to the parent plant. Easier to root, faster to fruit, good for fruits like plums. Slower than seedlings to plant but easier than grafting.', '2025-12-13 22:37:41');
INSERT INTO `planttype` VALUES (3, 'Grafting', 'Joins a desirable top (scion) to a root system (rootstock) for disease resistance or combining traits. Efficient and standard for many commercial trees. Offers hardiness and trait control.', '2025-12-13 22:37:41');

